"""LeCo FieldSpecs -- generated by scripts/gen_leco_fields.py from
wargame/reference/gap-analysis-leco.md + wargame/reference/arch-matrix-leco.md.

Regenerate with: uv run python scripts/gen_leco_fields.py
Hand edits are fine but will be overwritten on regeneration -- move any
permanent hand corrections into the generator or a follow-up patch step.
"""

from ..fields import FieldSpec, Widget


def _to_int(v):
    return int(v) if v not in (None, "") else v


def _to_float(v):
    return float(v) if v not in (None, "") else v


def _to_arg_list(v):
    s = str(v).strip()
    return s.replace('"', "").split() if s else None


def _from_arg_list(v):
    return " ".join(v) if isinstance(v, (list, tuple)) else (v or "")


def _to_int_or_float(v):
    if v in (None, ""):
        return v
    f = float(v)
    return int(f) if f >= 1 else f


